/* ============================================================
   SYSTEL — VRAIS SONS MP3 EMBARQUÉS BASE64 (fournis par l'utilisateur)
   Zéro dépendance fichier externe, zéro 404
   ============================================================ */
const SOUND_BIP = 'data:audio/mpeg;base64,';
const SOUND_ACQ = 'data:audio/mpeg;base64,';

let _bipNode = null;

function playBip(loop) {
  stopBip();
  try {
    _bipNode = new Audio(SOUND_BIP);
    _bipNode.loop = !!loop;
    _bipNode.volume = 1.0;
    const p = _bipNode.play();
    if (p) p.catch(() => {
      document.addEventListener('click', () => { if(_bipNode) _bipNode.play().catch(()=>{}); }, {once:true});
    });
  } catch(e) { console.warn('playBip', e); }
}

function stopBip() {
  if (_bipNode) {
    try { _bipNode.pause(); _bipNode.currentTime = 0; } catch(e) {}
    _bipNode = null;
  }
}

function playAck() {
  stopBip();
  try {
    const a = new Audio(SOUND_ACQ);
    a.volume = 1.0;
    a.play().catch(() => {});
  } catch(e) { console.warn('playAck', e); }
}

// Sons BER (tph_bouton + tph_auth enchaînés)
const SOUND_BER_BTN = 'data:audio/ogg;base64,';
const SOUND_BER_AUTH = 'data:audio/ogg;base64,';

function playBERStatut() {
  try {
    const btn = new Audio(SOUND_BER_BTN);
    btn.volume = 1.0;
    btn.play().catch(()=>{});
    btn.onended = () => {
      const auth = new Audio(SOUND_BER_AUTH);
      auth.volume = 1.0;
      auth.play().catch(()=>{});
    };
  } catch(e) { console.warn('playBERStatut', e); }
}
